  name: string;
  description: string;
  version: string;
  protocols: ProtocolConfig[];
  server: {
    port: number;
    host: string;
    ssl: boolean;
    authentication: boolean;
  };
  logging: {
    level: string;
    file: boolean;
    console: boolean;
  };
